mapper.select:
SELECT A.PROP_CD , A.PROP_NM , A.CAT_CD , (SELECT C.CAT_NM FROM TB_PROP_CATEGORY C WHERE C.CAT_CD = A.CAT_CD AND C.SUB_CAT_CD = '00') AS CAT_NM , A.SUB_CAT_CD , (SELECT C.CAT_NM FROM TB_PROP_CATEGORY C WHERE C.CAT_CD = A.CAT_CD AND C.SUB_CAT_CD = A.SUB_CAT_CD) AS SUB_CAT_NM , A.DEAL_TYPE , CASE A.DEAL_TYPE WHEN 'SELL' THEN '매매' WHEN 'JEONSE' THEN '전세' WHEN 'WOLSE' THEN '월세' WHEN 'SHORT' THEN '단기임대' ELSE '' END AS DEAL_TYPE_NM , A.SELL_PRICE, A.DEPOSIT, A.MONTHLY_RENT , A.AREA_EXCLUSIVE, A.ROOM_CNT, A.FLOOR_NO , A.ADDRESS, A.ADDRESS_DTL , A.LAT, A.LNG , A.BADGE_TYPE, A.SOLD_YN , DATE_FORMAT(A.RGT_DTM, '%Y-%m-%d') AS RGT_DTM FROM TB_PROPERTY A WHERE A.DEL_YN = 'N' AND A.USE_YN = 'Y' AND A.SOLD_YN = 'N' AND A.LAT IS NOT NULL AND A.LNG IS NOT NULL
AND A.LAT BETWEEN #{swLat} AND #{neLat} AND A.LNG BETWEEN #{swLng} AND #{neLng}
AND A.CAT_CD = #{catCd}
AND A.DEAL_TYPE = #{dealType}
ORDER BY A.RGT_DTM DESC LIMIT 100

SELECT A.PROP_CD , A.PROP_NM , A.CAT_CD , (SELECT C.CAT_NM FROM TB_PROP_CATEGORY C WHERE C.CAT_CD = A.CAT_CD AND C.SUB_CAT_CD = '00') AS CAT_NM , A.SUB_CAT_CD , (SELECT C.CAT_NM FROM TB_PROP_CATEGORY C WHERE C.CAT_CD = A.CAT_CD AND C.SUB_CAT_CD = A.SUB_CAT_CD) AS SUB_CAT_NM , A.DEAL_TYPE , CASE A.DEAL_TYPE WHEN 'SELL' THEN '매매' WHEN 'JEONSE' THEN '전세' WHEN 'WOLSE' THEN '월세' WHEN 'SHORT' THEN '단기임대' ELSE '' END AS DEAL_TYPE_NM , A.SELL_PRICE, A.DEPOSIT, A.MONTHLY_RENT , A.AREA_EXCLUSIVE, A.ROOM_CNT, A.FLOOR_NO , A.ADDRESS, A.BADGE_TYPE, A.SOLD_YN , A.ATCH_FILE_KEY , (SELECT CONCAT(F.SAVE_PATH, '/', F.SAVE_FILE_NM) FROM TB_UPLD_FILE F WHERE F.UPLD_FILE_CD COLLATE utf8mb4_unicode_ci = A.ATCH_FILE_KEY AND F.DEL_YN = 'N' ORDER BY F.FILE_SEQ ASC LIMIT 1) AS THUMB_PATH , DATE_FORMAT(A.RGT_DTM, '%Y-%m-%d') AS RGT_DTM FROM TB_PROPERTY A WHERE A.DEL_YN = 'N' AND A.USE_YN = 'Y'
AND A.CAT_CD = UPPER(#{catCd})
AND A.DEAL_TYPE = #{dealType}
AND (A.PROP_NM LIKE CONCAT('%', #{keyword}, '%') OR A.ADDRESS LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY CASE A.SOLD_YN WHEN 'N' THEN 0 ELSE 1 END ASC, A.RGT_DTM DESC LIMIT ${offset}, ${pageSize}

mapper.update:
UPDATE TB_PROPERTY
   SET VIEW_CNT = VIEW_CNT + 1
 WHERE PROP_CD = #{id}
